// mm/src/api/listDocuments.js
import axios from 'axios';
import { withAuthRetry } from './refresh';

const DEFAULT_API_BASE = 'https://manuscriptmagic.fowkes.xyz/services';
const API_BASE = process.env.REACT_APP_API_BASE_URL || DEFAULT_API_BASE;

const ACCESS_KEY = 'mm_accessToken';

function getAccessToken() {
  return localStorage.getItem(ACCESS_KEY) || '';
}

/**
 * Normalize backend document object
 * Backend returns:
 *   - DocumentId
 *   - OrigionalFileName
 *   - FileSize
 */
function normalizeDocument(raw = {}) {
  return {
    documentId: raw.DocumentId || null,
    filename: raw.OrigionalFileName || null,
    size: raw.FileSize ?? null, // bytes
  };
}

/**
 * List all documents for the authenticated user
 *
 * Endpoint: listDocuments.php
 * Requires:
 *   - Authorization: Bearer <token>
 *   - accessToken (query param for PHP)
 *
 * Backend returns:
 *   [
 *     { DocumentId, OrigionalFileName, FileSize }
 *   ]
 *
 * Returns:
 *   Success: { success: true, data: { documents: [] }, status }
 *   Failure: { success: false, error, status }
 */
export async function listDocuments() {
  const accessToken = getAccessToken();
  const url = `${API_BASE}/listDocuments.php`;

  if (!accessToken) {
    return {
      success: false,
      error: 'Missing access token',
      status: null,
    };
  }

  try {
    const response = await withAuthRetry(() =>
      axios.get(url, {
        headers: {
          Authorization: `Bearer ${accessToken}`,
          Accept: 'application/json',
        },
        params: { accessToken },
      })
    );

    // Backend returns array directly
    const rawDocs = Array.isArray(response.data) ? response.data : [];

    const documents = rawDocs.map(normalizeDocument);

    console.log('listDocuments success:', {
      status: response.status,
      count: documents.length,
      documents,
    });

    return {
      success: true,
      data: {
        documents,
      },
      status: response.status,
    };
  } catch (err) {
    const status = err?.response?.status ?? null;
    const backendError = err?.response?.data ?? null;
    const error = backendError || err?.message || 'Failed to list documents';

    console.error('listDocuments failed:', { status, error });

    return {
      success: false,
      error,
      status,
    };
  }
}
